use std::collections::HashMap;

struct GameState {
    board: Vec<Vec<char>>,
    width: usize,
    height: usize,
}
impl GameState {
    fn new(width: usize, height: usize) -> Self {
        GameState { board: vec![vec![' '; width]; height], width, height }
    }
}

trait BotStrategy {
    fn get_next_move(&self, state: &GameState) -> Option<(usize, usize)>;
}

struct SimpleBot;
impl BotStrategy for SimpleBot {
    fn get_next_move(&self, state: &GameState) -> Option<(usize, usize)> {
        Some((0, 0))
    }
}

struct SmartAI;
impl BotStrategy for SmartAI {
    fn get_next_move(&self, state: &GameState) -> Option<(usize, usize)> {
        None
    }
}

struct GameEngine {
    current_strategy: Box<dyn BotStrategy>
}
impl GameEngine {
    fn new(initial_strategy: Box<dyn BotStrategy>) -> Self {
        GameEngine { current_strategy: initial_strategy }
    }

    fn set_strategy(&mut self) -> Result<(), String> {
        let new_strategy: Box<dyn BotStrategy> = match std::env::args().nth(1).as_deref() {
            Some("simple") => Box::new(SimpleBot),
            Some("smart") => Box::new(SmartAI),
            _ => return Err("No valid bot strategy provided".to_string()),
        };
        self.current_strategy = new_strategy;
        Ok(())
    }

    fn run_turn(&self, state: &GameState) -> Option<(usize, usize)> {
        self.current_strategy.get_next_move(state)
    }
}

fn main() {
    let initial_state = GameState::new(10, 20);
    let mut engine = GameEngine::new(Box::new(SimpleBot));

    match engine.set_strategy() {
        Ok(_) => {
            if let Some(move_coords) = engine.run_turn(&initial_state) {
                println!("AI chose move: {:?}", move_coords);
            }
        },
        Err(e) => println!("Error initializing game: {}", e)
    }
}

use std::collections::HashMap;

trait Signer {
    fn sign(&self, data: &str) -> String;
}

struct SecretKeySigner { key: String }

impl Signer for SecretKeySigner {
    fn sign(&self, data: &str) -> String {
        format!("Signed with secret {} on data: {}", self.key, data)
    }
}

struct CombinationSigner { signer1: Box<dyn Signer>, signer2: Box<dyn Signer> }

impl Signer for CombinationSigner {
    fn sign(&self, data: &str) -> String {
        let sig1 = self.signer1.sign(data);
        let sig2 = self.signer2.sign(data);
        format!("Combined signature: [{}] | [{}]", sig1, sig2)
    }
}

fn process_message<T: Signer>(message: &str, signer: &T) -> String {
    signer.sign(message)
}

fn main() {
    let secret_key = String::from("super-secret-123");
    let primary_signer = SecretKeySigner { key: secret_key };

    let secondary_signer = SecretKeySigner { key: String::from("backup-key") };

    let combo_signer = CombinationSigner {
        signer1: Box::new(primary_signer),
        signer2: Box::new(secondary_signer)
    };

    let message_data = String::from("User payload data for JWT");

    println!("--- Processing with Combination Signer ---");
    let result1 = process_message(&message_data, &combo_signer);
    println!("Result 1: {}", result1);

    println!("
--- Demonstrating Type Coherence (Direct Call) ---");
    // This demonstrates that CombinationSigner implements the trait correctly
    let result2 = combo_signer.sign(&message_data);
    println!("Result 2: {}", result2);
}

use std::fmt::{self, Display};

trait Serializable {
    fn get_data(&self) -> Vec<f64>;
}

struct JsonData {
    values: Vec<f64>,
}

impl Serializable for JsonData {
    fn get_data(&self) -> Vec<f64> {
        self.values.clone()
    }
}

struct XmlData {
    elements: Vec<f64>,
}

impl Serializable for XmlData {
    fn get_data(&self) -> Vec<f64> {
        self.elements.clone()
    }
}

trait Normable {
    fn calculate_frobenius_norm(data: &str, data_vec: &[f64]) -> f64;
}

impl Normable for str {
    fn calculate_frobenius_norm(data: &str, data_vec: &[f64]) -> f64 {
        let sum_of_squares: f64 = data_vec.iter().map(|&x| x * x).sum();
        sum_of_squares.sqrt()
    }
}

fn process_and_benchmark<T: Serializable + ?Sized>(item: &T) -> f64 {
    let data_vec = item.get_data();
    str::calculate_frobenius_norm("BenchmarkRun", &data_vec)
}

fn main() {
    let json_struct = JsonData { values: vec![3.0, 4.0] };
    let xml_struct = XmlData { elements: vec![-1.0, 2.0] };

    let result_json = process_and_benchmark(&json_struct);
    let result_xml = process_and_benchmark(&xml_struct);

    println!("JSON Norm Result: {:.4}", result_json);
    println!("XML Norm Result: {:.4}", result_xml);
}

